package com.museumheist.game.character;import android.content.*;public final class SelectedCharacterStore{private static final String PREF="museum_heist_progress",KEY="selected_character_id";private final SharedPreferences p;public SelectedCharacterStore(Context c){p=c.getApplicationContext().getSharedPreferences(PREF,Context.MODE_PRIVATE);}public CharacterConfig loadSelectedCharacter(){return CharacterRepository.findById(p.getString(KEY,CharacterRepository.getDefault().getId()));}public void saveSelectedCharacter(CharacterConfig c){if(c!=null)p.edit().putString(KEY,c.getId()).apply();}}
